insert into public.tracks(slug,title,description,long_description,difficulty,icon,color,total_lessons,total_xp,order_index,tags) values
('acessibilidade','Acessibilidade','Construa interfaces inclusivas.','Semantica, foco, teclado, contraste, formularios acessiveis e testes de acessibilidade.','iniciante','♿','#2ECC71',8,900,13,array['frontend','a11y']),
('responsividade','Responsividade','Crie layouts para qualquer tela.','Mobile first, breakpoints, grids fluidos, imagens responsivas e testes em dispositivos.','iniciante','📱','#4DBBFF',8,920,14,array['frontend','layout']),
('projetos-praticos','Projetos Práticos','Construa produtos completos.','Projetos guiados de landing page, dashboard, app interativo, API integrada e portfolio.','intermediario','🚀','#F5A623',8,1200,15,array['projects','portfolio'])
on conflict(slug) do update set
  title=excluded.title,
  description=excluded.description,
  long_description=excluded.long_description,
  difficulty=excluded.difficulty,
  icon=excluded.icon,
  color=excluded.color,
  is_active=true,
  tags=excluded.tags;

