  ('responsividade','Tabelas em mobile','Transforme dados densos em UI usavel.','[{"module":"Responsivo Avancado","chapter":"Dados","title":"Tabela sem quebrar","text":"Dados tabulares precisam alternativa em telas pequenas.","challenge":"Crie tabela com scroll controlado ou cards no mobile.","validation":"validar ausencia de overflow horizontal","difficulty":"avancado"}]',140,1,5,'codigo',22,false),
  ('responsividade','Touch targets','Botoes confortaveis para toque.','[{"module":"Responsivo Avancado","chapter":"Interacao","title":"Toque seguro","text":"Alvos pequenos causam erro e frustracao.","challenge":"Ajuste botoes para tamanhos e espacos confortaveis.","validation":"validar dimensoes e gap","difficulty":"intermediario"}]',130,1,6,'codigo',18,false),
  ('responsividade','Revisao responsiva','Teste notebooks, mobile e desktop.','[{"module":"Responsivo Revisao","chapter":"QA","title":"Teste de viewport","text":"Responsividade precisa ser verificada em larguras reais.","challenge":"Corrija tres quebras em tamanhos diferentes.","validation":"validar sem corte e sem overflow","difficulty":"intermediario"}]',140,1,7,'codigo',24,false),
  ('responsividade','Projeto final responsivo','Construa uma pagina multiplataforma.','[{"module":"Responsivo Projeto","chapter":"Boss","title":"Produto fluido","text":"Una mobile first, grids, midia, toque e QA.","challenge":"Crie uma tela completa para celular, notebook e desktop.","validation":"validar layout completo responsivo","difficulty":"avancado"}]',220,3,8,'projeto',38,true),

  ('projetos-praticos','Landing page','Construa uma pagina de produto.','[{"module":"Projetos","chapter":"Landing","title":"Oferta clara","text":"Landing boa comunica valor e leva a acao.","challenge":"Crie hero, beneficios, prova social e CTA.","validation":"validar secoes principais","difficulty":"basico"}]',130,1,1,'projeto',24,false),
  ('projetos-praticos','Dashboard SaaS','Monte interface densa e escaneavel.','[{"module":"Projetos","chapter":"Dashboard","title":"Operacao diaria","text":"Dashboards precisam organizacao, hierarquia e dados claros.","challenge":"Crie cards, tabela, filtros e resumo.","validation":"validar dashboard completo","difficulty":"intermediario"}]',160,1,2,'projeto',30,false),
  ('projetos-praticos','To-do app','Crie app interativo com estado.','[{"module":"Projetos","chapter":"App","title":"Estado e persistencia","text":"Apps reais combinam UI, eventos e dados.","challenge":"Crie tarefas com filtros e localStorage.","validation":"validar CRUD local","difficulty":"intermediario"}]',170,1,3,'projeto',32,false),
  ('projetos-praticos','Cliente de API','Consuma dados e trate erro.','[{"module":"Projetos","chapter":"API","title":"Dados externos","text":"Produto real precisa lidar com carregamento, erro e vazio.","challenge":"Crie lista consumindo API simulada com loading e erro.","validation":"validar estados de dados","difficulty":"intermediario"}]',180,1,4,'projeto',34,false),
  ('projetos-praticos','Area autenticada','Desenhe fluxo de login e perfil.','[{"module":"Projetos","chapter":"Auth","title":"Sessao de usuario","text":"Auth combina formulario, feedback e estado protegido.","challenge":"Crie telas de login, perfil e rota protegida simulada.","validation":"validar fluxo auth","difficulty":"avancado"}]',190,1,5,'projeto',36,false),
  ('projetos-praticos','Portfolio dev','Apresente projetos com qualidade.','[{"module":"Projetos","chapter":"Portfolio","title":"Marca profissional","text":"Portfolio precisa mostrar contexto, papel e resultado.","challenge":"Crie portfolio com projetos, stack e contato.","validation":"validar secoes de portfolio","difficulty":"intermediario"}]',170,1,6,'projeto',30,false),
  ('projetos-praticos','Refatoracao final','Melhore acessibilidade e responsividade.','[{"module":"Projetos","chapter":"Refino","title":"Polimento final","text":"Produtos bons passam por revisao antes de publicar.","challenge":"Audite projeto para A11y, responsividade e performance.","validation":"validar checklist de qualidade","difficulty":"avancado"}]',180,1,7,'codigo',30,false),
  ('projetos-praticos','Capstone CodeQuest','Entregue um produto completo.','[{"module":"Projetos","chapter":"Boss","title":"Produto final","text":"Una HTML, CSS, JS, React, API, acessibilidade e responsividade.","challenge":"Construa um mini produto de aprendizado com progresso e missoes.","validation":"validar entrega capstone","difficulty":"avancado"}]',260,5,8,'projeto',50,true)
) as x(slug,title,description,content,xp,gems,ord,type,minutes,is_boss) on t.slug=x.slug
on conflict do nothing;

