update public.tracks t
set total_lessons=s.lesson_count,
    total_xp=s.total_xp
from (
  select track_id,count(*)::int as lesson_count,coalesce(sum(xp_reward),0)::int as total_xp
  from public.lessons
  where is_active=true
  group by track_id
) s
where t.id=s.track_id;
